CALCULATE_ROI_TOOL = {
    "name": "calculate_roi",
    "description": (
        "Calculate return on investment (ROI) and profit for a business decision. "
        "ROI is expressed as a percentage of the initial investment. "
        "Use this whenever the user asks about the profitability or return of an investment."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "investment": {
                "type": "number",
                "description": "Initial capital invested (must be > 0)."
            },
            "revenue": {
                "type": "number",
                "description": "Total revenue generated by the investment."
            },
            "cost": {
                "type": "number",
                "description": "Operating costs incurred (not including the initial investment)."
            }
        },
        "required": ["investment", "revenue", "cost"]
    }
}

def calculate_roi(investment: float, revenue: float, cost: float) -> dict:
    if investment <= 0:
        return {
            "error": "VALIDATION_ERROR",
            "message": "investment must be greater than zero.",
            "retryable": False,
        }
    profit = revenue - cost
    roi = profit / investment
    return {
        "roi_percent": round(roi * 100, 2),
        "profit": round(profit, 2),
        "net_margin_percent": round(profit / revenue * 100, 2) if revenue > 0 else 0,
        "breakeven_revenue": round(cost + investment, 2),
    }

import re

CLASSIFY_SUPPORT_TICKET_TOOL = {
    "name": "classify_support_ticket",
    "description": (
        "Classify a customer support ticket into a category and urgency level. "
        "Returns category (billing/technical/account/general) and urgency (high/medium/low)."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "subject": {"type": "string", "description": "Email subject line."},
            "body": {"type": "string", "description": "Email body text."}
        },
        "required": ["subject", "body"]
    }
}

_BILLING_TERMS = re.compile(
    r"\b(invoice|charge|refund|payment|bill|subscription|price|cost)\b", re.I
)
_TECHNICAL_TERMS = re.compile(
    r"\b(error|crash|bug|not working|broken|fail|exception|timeout)\b", re.I
)
_ACCOUNT_TERMS = re.compile(
    r"\b(login|password|account|access|locked|username|2fa|mfa)\b", re.I
)
_URGENT_TERMS = re.compile(
    r"\b(urgent|asap|immediately|critical|outage|down|emergency)\b", re.I
)

def classify_support_ticket(subject: str, body: str) -> dict:
    text = f"{subject} {body}"
    if _BILLING_TERMS.search(text):
        category = "billing"
    elif _TECHNICAL_TERMS.search(text):
        category = "technical"
    elif _ACCOUNT_TERMS.search(text):
        category = "account"
    else:
        category = "general"
    urgency = "high" if _URGENT_TERMS.search(text) else "medium"
    return {"category": category, "urgency": urgency}

import re

VALIDATE_ADDRESS_TOOL = {
    "name": "validate_address",
    "description": (
        "Validate a US postal address format. "
        "Checks that the zip code, state abbreviation, and street number are present and well-formed. "
        "Does not verify that the address physically exists."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "street": {"type": "string"},
            "city": {"type": "string"},
            "state": {"type": "string", "description": "Two-letter US state abbreviation, e.g. CA."},
            "zip_code": {"type": "string", "description": "5-digit or 9-digit ZIP code, e.g. 94105 or 94105-1234."}
        },
        "required": ["street", "city", "state", "zip_code"]
    }
}

US_STATES = {
    "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA",
    "HI","ID","IL","IN","IA","KS","KY","LA","ME","MD",
    "MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ",
    "NM","NY","NC","ND","OH","OK","OR","PA","RI","SC",
    "SD","TN","TX","UT","VT","VA","WA","WV","WI","WY",
    "DC","PR","GU","VI"
}

def validate_address(street: str, city: str, state: str, zip_code: str) -> dict:
    errors = []
    if not re.match(r'^\d+\s+\S', street.strip()):
        errors.append({"field": "street", "message": "Must begin with a street number."})
    if state.upper() not in US_STATES:
        errors.append({"field": "state", "message": f"{state!r} is not a valid US state abbreviation."})
    if not re.match(r'^\d{5}(-\d{4})?$', zip_code.strip()):
        errors.append({"field": "zip_code", "message": "Must be 5 or 9 digits (e.g. 94105 or 94105-1234)."})
    if errors:
        return {
            "valid": False,
            "errors": errors,
        }
    return {
        "valid": True,
        "normalised": {
            "street": street.strip().title(),
            "city": city.strip().title(),
            "state": state.strip().upper(),
            "zip_code": zip_code.strip(),
        }
    }

TAX_RATES = {"CA": 0.0725, "NY": 0.08, "TX": 0.0625, "WA": 0.065, "FL": 0.06}

def calculate_order_total(
    subtotal: float,
    discount_code: str | None,
    ship_to_state: str,
) -> dict:
    if subtotal <= 0:
        return {"error": "VALIDATION_ERROR",
                "message": "subtotal must be greater than zero.", "retryable": False}
    # Step 1: apply discount
    discount_pct = 0.0
    if discount_code:
        discount_pct = {"SAVE10": 0.10, "SAVE20": 0.20, "HALFOFF": 0.50}.get(
            discount_code.upper(), 0.0
        )
        if discount_pct == 0.0:
            return {"error": "VALIDATION_ERROR",
                    "message": f"Discount code {discount_code!r} is invalid.",
                    "retryable": False}
    discounted = subtotal * (1 - discount_pct)
    # Step 2: apply tax
    tax_rate = TAX_RATES.get(ship_to_state.upper(), 0.0)
    tax = discounted * tax_rate
    total = discounted + tax
    return {
        "subtotal": round(subtotal, 2),
        "discount_percent": round(discount_pct * 100, 1),
        "discounted_subtotal": round(discounted, 2),
        "tax_rate_percent": round(tax_rate * 100, 2),
        "tax": round(tax, 2),
        "total": round(total, 2),
        "currency": "USD",
    }

class ShoppingCartTools:
    def __init__(self):
        self._items: list[dict] = []

    def add_to_cart(self, name: str, price: float, quantity: int = 1) -> dict:
        if price < 0:
            return {"error": "VALIDATION_ERROR", "message": "price cannot be negative.", "retryable": False}
        self._items.append({"name": name, "price": price, "qty": quantity})
        return {"added": name, "cart_size": len(self._items), "subtotal": self._subtotal()}

    def remove_from_cart(self, name: str) -> dict:
        before = len(self._items)
        self._items = [i for i in self._items if i["name"] != name]
        if len(self._items) == before:
            return {"error": "NOT_FOUND", "message": f"{name!r} is not in the cart.", "retryable": False}
        return {"removed": name, "cart_size": len(self._items), "subtotal": self._subtotal()}

    def view_cart(self) -> dict:
        return {"items": list(self._items), "subtotal": self._subtotal(), "count": len(self._items)}

    def _subtotal(self) -> float:
        return round(sum(i["price"] * i["qty"] for i in self._items), 2)

    def get_tools(self) -> list[dict]:
        return [
            {"name": "add_to_cart",
             "description": "Add an item to the shopping cart.",
             "input_schema": {"type": "object",
                              "properties": {"name": {"type": "string"},
                                             "price": {"type": "number"},
                                             "quantity": {"type": "integer", "minimum": 1}},
                              "required": ["name", "price"]}},
            {"name": "remove_from_cart",
             "description": "Remove an item from the cart by name.",
             "input_schema": {"type": "object",
                              "properties": {"name": {"type": "string"}},
                              "required": ["name"]}},
            {"name": "view_cart",
             "description": "Show all items in the cart with the current subtotal.",
             "input_schema": {"type": "object", "properties": {}}},
        ]

    def dispatch(self, name: str, tool_input: dict) -> dict:
        return getattr(self, name)(**tool_input)
